class Solution {
    func segregate(_ nums: [Int]) -> [Int] {
        var result = nums
        var left = 0
        var right = result.count - 1
        while left < right {
            if result[left] == 0 {
                left += 1
            } else if result[right] == 1 {
                right -= 1
            } else {
                result.swapAt(left, right)
                left += 1
                right -= 1
            }
        }
        return result
    }
}

