class Solution {
    func leftMostColumnWithOne(_ binaryMatrix: BinaryMatrix) -> Int {
        let dims = binaryMatrix.dimensions()
        let rows = dims[0]
        let cols = dims[1]

        var row = 0
        var col = cols - 1
        var foundOne = false

        while row < rows && col >= 0 {
            if binaryMatrix.get(row, col) == 1 {
                col -= 1
                foundOne = true
            } else {
                row += 1
            }
        }

        return foundOne ? col + 1 : -1
    }
}

