        if numRows == 1 {
            return [[1]]
        }
        ans = [[1]]
        for i in 1..<numRows {
            var oldArray = ans[i - 1]
            var newArray = Array(repeating : 1 , count : oldArray.count + 1)
            newArray[0] = 1
            for j in 1..<(newArray.count - 1) { // j index of new array
                newArray[j] = oldArray[j - 1] + oldArray[j] 
            }
            newArray[newArray.count - 1] = 1
            ans.append(newArray)
        }
       return ans
    }
}

